#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Post-recovery hardening (exit-0-safe): revive Channel-1 birth feeds (NRD+CZDS timers)
and stop the async-ramp crash-loop experiment (targets 1024-2048 lanes a 100-conn box
can't hold -> pure churn). Reports before/after. Pure systemctl, no DB writes."""
import os,sys,json,time,subprocess,base64,urllib.request,urllib.error
def sh(c,t=40):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t); return (r.stdout+r.stderr).strip()
    except Exception as e: return "ERR:%s"%e
out={"kind":"harden","ts":int(time.time())}
try:
    # discover relevant units
    allu=sh("systemctl list-unit-files --no-legend 2>/dev/null | awk '{print $1}'")
    units=allu.split()
    def find(pats):
        import re
        return [u for u in units if any(p in u.lower() for p in pats)]
    nrd=find(['nrd']); czds=find(['czds']); ramp=find(['ramp'])
    out["found"]={"nrd":nrd,"czds":czds,"ramp":ramp}
    # REVIVE channel-1: enable+start timers (and one-shot the service to backfill now)
    revived=[]
    for u in nrd+czds:
        if u.endswith('.timer'):
            revived.append(u+":"+sh("systemctl enable --now %s 2>&1 | tail -1; systemctl is-active %s"%(u,u)))
    # fire a one-shot run now for the .service to catch up
    for u in nrd+czds:
        if u.endswith('.service'):
            sh("systemctl start %s 2>&1"%u, t=20)
    out["channel1_revived"]=revived
    # TAME async-ramp churn: stop+disable the ramp probe (keep steady enrich-async@1)
    tamed=[]
    for u in ramp:
        tamed.append(u+":"+sh("systemctl stop %s 2>&1; systemctl disable %s 2>&1 | tail -1; systemctl is-active %s"%(u,u,u)))
    out["async_ramp_tamed"]=tamed
    out["nrd_timer_state"]=sh("systemctl list-timers --all --no-legend 2>/dev/null | grep -iE 'nrd|czds' | awk '{print $5,$NF}'")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    env=envf("/etc/atlas/autopull.env")
    tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    br=env.get("STATUS_BRANCH","main"); api="https://api.github.com"; path="status/hetzner/harden.json"
    if tok and repo:
        url="%s/repos/%s/contents/%s"%(api,repo,path); sha=None
        try:
            r=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"harden","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":br}
        if sha: body["sha"]=sha
        for _ in range(4):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
